  ('locality-10ced7e2-moex-00231', 'locality-10ced7e2', 'locality-10ced7e2-moex-111-3a7b2121', 'sub-locality-10ced7e2-03', NULL, 'single_choice', '有關非營利組織的敘述，下列何者正確？', '["組織收入多寡與其所提供的公共服務績效之間，並不一定是正相關", "利潤由組織內的財源提供者共享", "非營利組織的成立門檻為50人", "非營利組織必須與政府區隔，不能接受政府財務支持"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:12+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "313", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "人事行政"}'::jsonb, NULL),
  ('locality-10ced7e2-moex-00232', 'locality-10ced7e2', 'locality-10ced7e2-moex-111-3a7b2121', 'sub-locality-10ced7e2-03', NULL, 'single_choice', '有關政府採用民營化的敘述，下列何者較為正確？', '["易產生社會服務等級化疑慮", "通常以行政法人化加以執行", "擴大政府的職權及用人幅度", "意指政府釋出全部的持股"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:12+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "313", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "人事行政"}'::jsonb, NULL),
  ('locality-10ced7e2-moex-00233', 'locality-10ced7e2', 'locality-10ced7e2-moex-111-3a7b2121', 'sub-locality-10ced7e2-03', NULL, 'single_choice', '有關審議民主的敘述，下列何者正確？', '["為了讓議題討論結果更具一致性，應選擇同質性較高的參與者", "不論採用何種審議形式，都強調參與者對議題的充分討論", "審議過程可取代代議制度的決策程序", "審議民主可確保理性最佳決策的達成"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:12+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "313", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "人事行政"}'::jsonb, NULL),
  ('locality-10ced7e2-moex-00234', 'locality-10ced7e2', 'locality-10ced7e2-moex-111-3082b5f1', 'sub-locality-10ced7e2-04', NULL, 'essay', '甲與行政機關乙締結行政契約。其後行政機關乙認為締約後有情事重大
變更，乃向甲發公函逕行終止該契約。請問行政機關乙逕行終止該契約
之行為性質為何？若甲認為行政機關乙逕行終止該契約並不合法時，甲
得如何尋求救濟？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:12+00:00", "source_pdf_sha1": "604b45da09c0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "313", "s": "0709", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "人事行政"}'::jsonb, NULL),
  ('locality-10ced7e2-moex-00235', 'locality-10ced7e2', 'locality-10ced7e2-moex-111-3082b5f1', 'sub-locality-10ced7e2-04', NULL, 'essay', '甲生前為人作保，擔任其好友乙向丙借款 5 千萬之保證人，清償期為 110
年 12 月 15日。甲在 110 年 2 月9 日死亡，其子丁繼承其遺產。丁向國
稅局申報遺產稅時，主張其遺產總額應扣除甲生前所負之該筆保證債
務。但國稅局則以該筆主債務尚未屆清償期，故丁於繼承時尚未確定代
負履行之責，乃將該筆保證債務剔除。國稅局核定丁遺產稅之處分於110
年 8 月 8 日送達，丁於收受該處分書後隨即繳納遺產稅。其後乙於上開
債務清償期屆至後並未清償，且逃往外國不知去向。丙就乙之財產強制
執行無效果，乃請求丁代負履行責任。丁於代負清償該筆 5千萬之債務
後，深感自己繳了太多遺產稅。請問丁得否請求國稅局依據行政程序法
重開程序之規定，重新核定其遺產稅額？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:12+00:00", "source_pdf_sha1": "604b45da09c0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "313", "s": "0709", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "人事行政"}'::jsonb, NULL),
  ('locality-10ced7e2-moex-00236', 'locality-10ced7e2', 'locality-10ced7e2-moex-111-3082b5f1', 'sub-locality-10ced7e2-04', NULL, 'single_choice', '依實務見解，關於緊急命令，下列敘述何者正確？', '["總統僅於應付重大財政危機時，得經行政院會議之議決，發布緊急命令", "總統發布緊急命令之前，應徵詢立法院院長之意見", "緊急命令之內容應力求周延，以不得再授權為補充規定即可逕予執行為原則", "緊急命令得永久變更或取代相關法律之效力 31330"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:12+00:00", "source_pdf_sha1": "604b45da09c0", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "313", "s": "0709", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "人事行政"}'::jsonb, NULL),
  ('locality-10ced7e2-moex-00237', 'locality-10ced7e2', 'locality-10ced7e2-moex-111-3082b5f1', 'sub-locality-10ced7e2-04', NULL, 'single_choice', '關於公益原則，下列敘述何者正確？', '["主管機關發現核准之生活扶助處分，確屬錯誤，即得依公益原則，無條件撤銷原處分", "主管機關基於避免法定傳染病快速蔓延之重大公益，得將與患者有過接觸之人，令入指定之處 所施行適當期間之必要強制隔離處置", "主管機關出於增進交通流暢度等公益考量，得不經相關程序，徵收民眾之土地，拓寬道路", "主管機關本於維持治安之公益要求，得依職權訂定行政規則禁止製造、運輸、販售、攜帶與公 開陳列類似真槍之玩具槍"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:12+00:00", "source_pdf_sha1": "604b45da09c0", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "313", "s": "0709", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "人事行政"}'::jsonb, NULL),
  ('locality-10ced7e2-moex-00238', 'locality-10ced7e2', 'locality-10ced7e2-moex-111-3082b5f1', 'sub-locality-10ced7e2-04', NULL, 'single_choice', '關於人民與國家之法律關係，下列敘述何者錯誤？', '["依目前行政法院見解，公立學校教師與學校間之法律關係為行政契約", "全民健康保險特約醫事機構與衛生福利部中央健康保險署簽訂之特約，依司法院解釋係屬行政 契約", "退除役軍職人員與臺灣銀行間優惠存款利息爭議，依司法院解釋應由行政法院審理", "私立大學學生遭學校撤銷學籍爭議，依司法院解釋應由行政法院審理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:12+00:00", "source_pdf_sha1": "604b45da09c0", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "313", "s": "0709", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "人事行政"}'::jsonb, NULL),
  ('locality-10ced7e2-moex-00239', 'locality-10ced7e2', 'locality-10ced7e2-moex-111-3082b5f1', 'sub-locality-10ced7e2-04', NULL, 'single_choice', '依地方制度法之規定，有關自治條例，下列敘述何者錯誤？', '["經地方立法機關議決後，均須送請行政院核定", "得對違反地方自治事項之行政義務者處以罰鍰", "地方自治團體之組織，應以自治條例規定之", "上級政府認定其規定與中央法令牴觸者，得予以函告無效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:12+00:00", "source_pdf_sha1": "604b45da09c0", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "313", "s": "0709", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "人事行政"}'::jsonb, NULL)
